Proof.
  induction l1 as [| h l1' IH]; intros.
  - simpl. unfold union, singleton.
    bdestruct (y =? x). lia. reflexivity.
  - simpl. unfold union, singleton.
    bdestruct (y =? h);
    rewrite IH; auto;
    simpl; unfold union, singleton;
    bdestruct (y =? h); lia.
Qed.
